func buildHTMXDemoSteps(current int) []steps.Step {
	labels := []string{
		"Create an account",
		"Select a plan",
		"Checkout",
		"Get started",
	}

	result := make([]steps.Step, 0, len(labels))
	for i, label := range labels {
		status := steps.StatusUpcoming
		switch {
		case i+1 < current:
			status = steps.StatusCompleted
		case i+1 == current:
			status = steps.StatusCurrent
		}

		result = append(result, steps.Step{
			ID:        fmt.Sprintf("steps-htmx-%d", i+1),
			Label:     label,
			AriaLabel: label,
			Status:    status,
		})
	}

	return result
}

